SELECT SUM(profit_loss) AS total_profit_loss
FROM user_portfolios
WHERE user_id = 1;

SELECT stock_symbol, company_name, market_cap, ipo_date, ceo_name
FROM stocks
WHERE last_update = (SELECT MAX(last_update) FROM stocks);

SELECT company_name
FROM stocks
WHERE market_cap > 100000000000;

SELECT stock_symbol, company_name, market_cap
FROM stocks
WHERE market_cap = (SELECT MAX(market_cap) FROM stocks);

SELECT company_name
FROM stocks
WHERE stock_id = 1;

SELECT title
FROM news_articles
WHERE stock_id = 1;
